mapper.select:
SELECT eo.id AS orderId, eo.donation_amount AS donationAmount, eo.redemption_amount AS redemptionAmount, eo.shares AS shares, eo.status, eo.settlement_date AS settlementDate, eo.create_at AS createAt, ep.period, ep.earning_yield AS earningYield, b.brand_name AS sponsorName FROM oasis_equity_order eo INNER JOIN oasis_equity_period ep ON eo.equity_period_id = ep.id INNER JOIN brand b ON eo.sponsor_brand_id = b.id WHERE ep.oasis_id = #{dto.oasisId}
AND eo.status = #{dto.status}
And locate(#{dto.q}, b.brand_name)>0
And ep.period = #{dto.period}
ORDER BY eo.create_at DESC
